+        .full_reindex(&storage, &cfg_first)
+        .await
+        .unwrap();
+    assert_eq!(first_progress.events_indexed, 5);
+    assert!(!first_progress.caught_up);
+
+    let writer_first = pipeline_first.into_writer();
+
+    let recovery_start = Instant::now();
